## Code Example

```javascript
// TrafficExperiment CRD controller reconcile function
async function reconcileTrafficExperiment(exp) {
  const { service, canaryImage, canaryPercent, steps, namespaceSelector } = exp.spec;
  const currentStatus = exp.status || { phase: 'Initializing', currentStep: 0, canaryWeight: 0 };

  // Target namespaces for rollout
  const namespaces = await getTargetNamespaces(namespaceSelector);

  // Initialize or update traffic split across namespaces
  for (const ns of namespaces) {
    await updateTrafficSplit(service, canaryPercent, ns);
  }

  // Monitor latency SLI and trigger rollback if needed
  const currentLatency = await observeLatencySLI(namespaces);
  if (currentLatency > exp.spec.latencyThreshold) {
    await triggerRollback(exp, namespaces);
    return;
  }

  // Progress to next step if time window met and metrics healthy
  if (shouldPromote(currentStatus, steps)) {
    currentStatus.currentStep++;
    currentStatus.canaryWeight = calculateNewWeight(steps[currentStatus.currentStep]);
  }

  // Update status with latest observations
  exp.status = {
    ...currentStatus,
    observedLatencySLI: currentLatency,
    lastUpdated: new Date().toISOString()
  };
}
```

