## Code Example

```javascript
// Pseudo-reconciler scaffold (high level)
class BackpressureRouterReconciler {
  async reconcile(request) {
    const { namespace, crd } = request;
    const generation = crd.metadata.generation;

    // 1. Fetch current EnvoyFilter state
    const currentFilters = await this.meshClient.getEnvoyFilters(namespace);

    // 2. Compute desired state from CRD
    const desired = this.computeDesiredState(crd.spec);

    // 3. Diff and apply (idempotent)
    if (!deepEqual(currentFilters, desired)) {
      await this.meshClient.applyEnvoyFilters(namespace, desired);
    }

    // 4. Update SLA dashboard
    await this.dashboardClient.updateMetrics(namespace, desired);

    // 5. Update status with generation
    await this.updateStatus(namespace, { appliedGeneration: generation });
  }

  async onError(err, request) {
    // Rollback to last-known-good ConfigMap
    const lastGood = await this.k8s.getConfigMap('backpressure-rollback');
    await this.meshClient.applyEnvoyFilters(request.namespace, lastGood);
    this.metrics.increment('backpressure_rollback_total');
  }
}
```

