func (r *GPUQuotaReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
    ns := &corev1.Namespace{}
    if err := r.Get(ctx, req.NamespacedName, ns); err != nil {
        return ctrl.Result{}, client.IgnoreNotFound(err)
    }

    gpuQuota := &GPUQuota{}
    if err := r.Get(ctx, req.NamespacedName, gpuQuota); err != nil {
        return ctrl.Result{}, client.IgnoreNotFound(err)
    }

    available GPUs, err := r.getAvailableGPUs(ns.Name)
    if err != nil {
        return ctrl.Result{}, err
    }

    if gpuQuota.Spec.Burst.Enabled {
        if isWithinBurstWindow(gpuQuota) {
            return r.reconcileBurst(ctx, gpuQuota, availableGPUs)
        }
    }

    return r.enforceQuota(ctx, gpuQuota, availableGPUs)
}
```

