// NamespaceFairness CRD definition
type NamespaceFairnessSpec struct {
    Namespace    string  `json:"namespace"`
    Weight       float64 `json:"weight"`
    MaxConcurrency int   `json:"maxConcurrency"`
    BurstFactor  int     `json:"burstFactor"`
}

// Scheduler plugin implements Filter, Score, and PostFilter hooks
type NamespaceFairnessPlugin struct {
    client     client.Client
    informer   cache.SharedIndexInformer
    fairConfig map[string]*NamespaceFairnessSpec
}

func (p *NamespaceFairnessPlugin) Filter(ctx context.Context, state *framework.CycleState, pod *v1.Pod, nodeInfo *framework.NodeInfo) *framework.Status {
    ns := pod.Namespace
    fairness, exists := p.fairConfig[ns]
    if !exists {
        return framework.NewStatus(framework.Success, "no fairness policy")
    }

    currentUsage := p.getNamespaceUsage(ns)
    if currentUsage >= fairness.MaxConcurrency {
        return framework.NewStatus(framework.Unschedulable, "namespace concurrency limit reached")
    }
    return framework.NewStatus(framework.Success, "")
}

func (p *NamespaceFairnessPlugin) PostFilter(ctx context.Context, state *framework.CycleState, pod *v1.Pod, filteredNodeStatuses framework.NodeToStatusMap) (*framework.PostFilterResult, *framework.Status) {
    // Attempt preemption of lower-priority pods in the same namespace
    preemptiblePods := p.getLowerPriorityPods(pod)
    if len(preemptiblePods) > 0 {
        p.evictPods(preemptiblePods)
        return &framework.PostFilterResult{NominatingNodeName: filteredNodeStatuses.NodeName()}, framework.NewStatus(framework.Success, "preemption triggered")
    }
    return nil, framework.NewStatus(framework.Unschedulable, "no preemptible pods")
}

func (p *NamespaceFairnessPlugin) Score(ctx context.Context, state *framework.CycleState, pod *v1.Pod, nodeName string) (int64, *framework.Status) {
    fairness := p.getNamespaceFairness(pod.Namespace)
    if fairness == nil {
        return 100, framework.NewStatus(framework.Success, "")
    }
    return int64(fairness.Weight * 100), framework.NewStatus(framework.Success, "")
}

// Reconciliation loop
func (p *NamespaceFairnessPlugin) reconcile(ctx context.Context) {
    for {
        select {
        case <-ctx.Done():
            return
        case <-time.After(30 * time.Second):
            p.refreshFairConfig()
            p.reconcileNamespaceLimits()
        }
    }
}
```

